module top_module(
  input obf_in1,
  input in2,
  output out_and,
  output out_or,
  output out_not,
  output out_xor,
  output out_xnor
);// AND gate
  assign out_and = obf_in1 & in2;

  // OR gate
  assign out_or = obf_in1 | in2;

  // NOT gate
  assign out_not = ~obf_in1;

  // XOR gate
  assign out_xor = obf_in1 ^ in2;

  // XNOR gate
  assign out_xnor = ~(obf_in1 ^ in2);

endmodule
